import React, { useEffect, useState } from "react";
import axiosInstance from "../lib/instance";

function Store() {
  const [stores, setStores] = useState([]);
  const [loading, setLoading] = useState(false);
  const [ratings, setRatings] = useState({});

  // ✅ Fetch stores
  const fetchStores = async () => {
    setLoading(true);
    try {
      const res = await axiosInstance.get("/stores/all");

      console.log("Stores:", res.data);

      if (res?.data?.data) {
        setStores(res.data.data);
      }
    } catch (error) {
      console.error("Fetch stores error:", error);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchStores();
  }, []);

  // ✅ Handle rating input
  const handleRatingChange = (storeId, value) => {
    setRatings((prev) => ({
      ...prev,
      [storeId]: value,
    }));
  };

  // ✅ Submit rating
  const handleSubmitRating = async (storeId) => {
    try {
      const value = ratings[storeId];

      if (!value || value < 1 || value > 5) {
        alert("Enter rating between 1 and 5");
        return;
      }

      const res = await axiosInstance.post(
        `/stores/${storeId}/rating`,
        { value: Number(value) }
      );

      console.log("Rating submitted:", res.data);

      if (res?.data?.success) {
        await fetchStores(); // 🔥 refresh table

        // clear input
        setRatings((prev) => ({
          ...prev,
          [storeId]: "",
        }));
      }
    } catch (error) {
      console.error("Rating error:", error);

      const msg =
        error?.response?.data?.message ||
        error?.message ||
        "Failed to submit rating";

      alert(msg);
    }
  };

  // ✅ Stats
  const totalStores = stores.length;

  return (
    <div>
      {/* Stats */}
      <div className="grid grid-cols-3 gap-4 mb-6">
        <div className="bg-white p-4 rounded shadow">
          Stores: {totalStores}
        </div>
      </div>

      {/* Table */}
      <div className="bg-white p-4 rounded shadow">
        <h2 className="font-semibold mb-3">Stores</h2>

        {loading ? (
          <p>Loading...</p>
        ) : (
          <table className="w-full text-center">
            <thead className="bg-indigo-600 text-white">
              <tr>
                <th>Name</th>
                <th>Owner</th>
                <th>Address</th>
                <th>Avg Rating</th>
                <th>Your Rating</th>
                <th>Give Rating</th>
              </tr>
            </thead>

            <tbody>
              {stores.length > 0 ? (
                stores.map((s) => (
                  <tr key={s.id} className="border-b">
                    <td>{s.name}</td>
                    <td>{s.user?.name || "-"}</td>
                    <td>{s.address}</td>

                    {/* Avg rating */}
                    <td>
                      {s.averageRating !== undefined
                        ? s.averageRating.toFixed(1)
                        : 0}
                    </td>

                    {/* Your rating */}
                    <td>{s.yourRating || "-"}</td>

                    {/* Give rating */}
                    <td>
                      <div className="flex items-center gap-2 justify-center">
                        <input
                          type="number"
                          min="1"
                          max="5"
                          value={ratings[s.id] || ""}
                          onChange={(e) =>
                            handleRatingChange(s.id, e.target.value)
                          }
                          className="border w-16 p-1 rounded text-center"
                          placeholder="1-5"
                        />

                        <button
                          onClick={() => handleSubmitRating(s.id)}
                          className="bg-indigo-600 text-white px-2 py-1 rounded text-sm"
                        >
                          Submit
                        </button>
                      </div>
                    </td>
                  </tr>
                ))
              ) : (
                <tr>
                  <td colSpan="6">No stores found</td>
                </tr>
              )}
            </tbody>
          </table>
        )}
      </div>
    </div>
  );
}

export default Store;
